INSERT INTO quiz_question (id, word_bank_id, contextual_cloze, chinese_translation, correct_answer, distractor1, distractor2, distractor3, explanation_root_affix, explanation_mnemonic, created_at, updated_at) VALUES
('d9bd1ee0-350b-56f5-b048-05b480cda9e2', '2cc8c787-2cbf-42d3-b9c3-8b009225321c', 'The school''s annual sports day is scheduled for ___ 15th.', '學校一年一度的運動會定於四月十五日舉行。', 'April', 'Monday', 'Summer', 'Night', 'April 為名詞，代表曆法中的四月。', '依照月份順序記憶：March (三月) → April (四月) → May (五月)。', '2026-07-06 23:30:43', '2026-07-06 23:30:43'),
('b325ff3c-39a0-5769-937a-e0c49970670e', 'eaaceb04-ade0-4fb3-9b61-d4dde892703b', 'The hospital staff must ___ the medication carefully to ensure the patient''s safety.', '醫護人員必須小心地給予藥物，以確保病人的安全。', 'administer', 'purchase', 'describe', 'celebrate', 'ad- (朝向) + minister (僕人/服務者) → 像僕人一樣去服務他人 → 引申為管理、執行或給予。', 'remember ''minister'' (部長/大臣) is someone who ''administers'' (管理/執行) important affairs.', '2026-07-06 17:47:19', '2026-07-06 17:47:19'),
('453160bf-5947-5602-95c6-d6b6a83fbc6a', 'c3b74e7c-358e-444e-8450-ddbfb2f1dd72', 'The students are having lunch now, so they will play outside in the ___.', '學生們現在正在吃午餐，所以他們會在下午到外面玩。', 'afternoon', 'morning', 'night', 'autumn', 'after (在...之後) + noon (中午) → 中午之後的時間。', '記住 after 是「之後」，noon 是「中午」，中午之後就是下午。', '2026-07-06 13:24:18', '2026-07-06 13:24:18'),
('2d63bcba-0291-5586-9d87-0d069df18cee', '22ae09b7-77ae-4a42-adb0-a030a9dc0549', 'The talented ___ spent years studying classical painting before opening her own gallery.', '這位才華橫溢的藝術家在開設自己的畫廊之前，花了數年時間研究古典繪畫。', 'artist', 'doctor', 'athlete', 'lawyer', 'art (藝術) + -ist (表示「……的人」或「……家」的字尾) → 藝術家', '看到 -ist 字尾，通常是指從事某種專業的人，例如 artist (藝術家) 或 scientist (科學家)。', '2026-07-07 00:33:47', '2026-07-07 00:33:47'),
('cf2a40f3-7908-5546-bf54-bf362db1285e', 'e57931b3-f580-4d8c-96b1-dd342e262c59', 'The doctor tried to ___ the patient that the surgery would be successful.', '醫生試圖向病人保證手術會很成功。', 'assure', 'warn', 'remind', 'notify', '字根為 ad- (朝向) + sure (確定的) → 使某人感到確定 → 向...保證。', '將字拆解為 as + sure，想像讓某人感覺如同(as)確定(sure)的一樣 → 向某人保證。', '2026-07-07 01:33:56', '2026-07-07 01:33:56'),
('515de1ff-d1f3-5d81-8806-ee8d5ccc9d72', 'ae2ae4c9-6956-428b-9530-5c5718a76134', 'The lumberjack used a sharp ___ to chop down the old oak tree in the forest.', '那位伐木工使用一把鋒利的斧頭來砍倒森林裡的那棵老橡樹。', 'axe', 'hammer', 'shovel', 'ladder', 'axe 為名詞，指用於砍伐木材的工具。', '想像伐木工 (lumberjack) 拿著 axe 砍樹的畫面。', '2026-07-07 04:28:07', '2026-07-07 04:28:07'),
('04243f8c-4ec6-5958-be9d-123799230606', '2c8847af-b6ec-4e33-a281-e5b0dd2159bd', 'The movie was so ___ that I fell asleep in the cinema.', '這部電影太乏味了，以至於我在電影院睡著了。', 'boring', 'exciting', 'beautiful', 'expensive', 'bore (使厭煩) + ing (形容詞字尾，用來修飾事物)', '想像你在看一部很無聊的電影，看著看著就睡著了 → boring。', '2026-07-07 05:10:03', '2026-07-07 05:10:03'),
('893712a0-1b22-5a8c-8361-3ec3fe1cd69a', '0a9ba8c9-d917-45ea-a18c-6fc68b5fa460', '___ is a sport where you roll a heavy ball to hit pins.', '___ 是一種用滾動沉重的球來擊中球瓶的運動。', 'Bowling', 'Soccer', 'Tennis', 'Basketball', '動詞 + ing 字尾可以轉化為名詞，表示一種活動或運動。', '想像球在球道上滾動並擊中球瓶的樣子 → bowling (保齡球運動)', '2026-07-07 08:08:42', '2026-07-07 08:08:42'),
('ad4d6842-bb9e-51de-ae28-50304dddbba6', '287a4af9-20ba-4720-be95-e468373764d1', 'I want to buy a new ___ to take photos of my cat.', '我想買一台新照相機來幫我的貓拍照。', 'camera', 'watch', 'pencil', 'window', 'camera 源自拉丁語，原意為「暗室」。', '想像在暗室 (camera) 中捕捉美照！', '2026-07-07 02:07:26', '2026-07-07 02:07:26'),
('9ad8e111-cbda-5baf-8123-d029376829d6', 'cd227fc1-001a-4012-b59d-fff188208bcb', 'I bought some ___ for my little sister at the supermarket.', '我在超市幫我妹妹買了一些糖果。', 'candy', 'bread', 'soap', 'salt', 'candy 指甜味的東西，通常指糖果。', '想像一個 candy cane (糖果棒) 的形狀，記住它是甜甜的糖果。', '2026-07-07 02:20:55', '2026-07-07 02:20:55'),
('6a0cede5-6dba-5379-8a72-51a9549215d2', 'ec13042a-727a-4875-a281-5d1e2bacc420', 'The seasons ___ from summer to autumn.', '季節從夏天轉變為秋天。', 'change', 'jump', 'walk', 'cook', 'change (v.) 表示變換', 'change (v.) 變換 → 季節的變化用 change', '2026-07-07 03:09:56', '2026-07-07 03:09:56'),
('c5636849-1a54-5cfe-97f9-0a8ecfcfa452', 'a9da8ce5-0a34-4f7c-bab7-b071db691ea1', 'Please put the cookies on a small ___.', '請把餅乾放在一個小盤子上。', 'dish', 'spoon', 'fork', 'cup', 'dish 在這裡當名詞，意思是盤子。', 'dish 聽起來像底，可以想像放在食物底下的盤子。', '2026-07-07 04:51:24', '2026-07-07 04:51:24'),
('7429b85b-aece-56a6-8115-f4b30a85eff2', 'c4f5942a-678d-48f2-bbd4-e4002e5be424', 'I read this book because it is very ___.', '我讀這本書是因為它非常有趣。', 'interesting', 'delicious', 'difficult', 'heavy', 'interest (興趣) + ing (形容詞字尾)', 'interest (興趣) + ing (令人...) → interesting (有趣的)', '2026-07-05 05:39:57', '2026-07-05 05:39:57');
